1	const PROCESSING_FEE = 5;
2	const SWORD_BASE_PREMIUM = 100;
3	const AMULET_BASE_PREMIUM = 60;
4	const STAFF_BASE_PREMIUM = 80;
5	
6	const POTION_BASE_PREMIUM = 40;
7	
8	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
9	  sword: SWORD_BASE_PREMIUM,
10	  amulet: AMULET_BASE_PREMIUM,
11	  staff: STAFF_BASE_PREMIUM,
12	  potion: POTION_BASE_PREMIUM,
13	};
14	
15	type Item = { type: string };
16	type QuoteStep = { op: "quote"; items: Item[] };
17	type Step = QuoteStep;
18	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
19	
20	const basePremiumFor = (item: Item): number => BASE_PREMIUM_BY_TYPE[item.type];
21	
22	const quoteStep = (step: QuoteStep): { premium: number } => {
23	  const itemsBase = step.items.reduce((sum, item) => sum + basePremiumFor(item), 0);
24	  return { premium: itemsBase + PROCESSING_FEE };
25	};
26	
27	export const runScenario = (scenario: Scenario): { results: { premium: number }[] } => {
28	  return { results: scenario.steps.map(quoteStep) };
29	};
