44	  // Component pricing
45	  it.todo("2 runes → 55 G premium (50 base + 5 fee)");
46	  it.todo("3 runes → 65 G premium (60 base block + 5 fee)");
47	  it.todo("4 runes → 105 G premium (100 base + 5 fee, no block)");
48	  it.todo("7 runes → 180 G premium (175 base + 5 fee)");
49	  it.todo("2 runes + 1 moonstone → 80 G premium (75 base, no block since different types)");
50	  it.todo("3 runes + 3 moonstones → 125 G premium (120 base, two separate blocks)");
51	
52	  // Item-specific modifiers (cursed, high enchantment)
53	  it.todo("cursed sword (enchantment 3) → curse surcharge 50%: 100 + 50 + 5 = 155 G");
54	  it.todo("sword with enchantment 5 → high-enchant surcharge 30%: 100 + 30 + 5 = 135 G");
55	  it.todo("sword with enchantment 4 → no high-enchant surcharge: 100 + 5 = 105 G");
56	  it.todo("cursed sword with enchantment 5 → both surcharges: 100 + 50 + 30 + 5 = 185 G");
57	
58	  // Policy-wide modifiers
59	  it.todo("customer with 2 years → loyalty discount 20% applies");
60	  it.todo("customer with 0 years → no loyalty discount");
61	
62	  // Modifier scope on multi-item policies
63	  it.todo("cursed sword + plain amulet → curse applies to sword only: 100+60+50+5 = 215 G");
64	
65	  // First insurance surcharge
66	  it.todo("first insurance per item: +10% per item base premium");
67	
